class Solution:
    def strangePrinter(self, s: str) -> int:
        n = len(s)
        dp = [[0] * n for _ in range(n)]
        for i in range(n):
            dp[i][i] = 1
        for l in range(1, n):
            for i in range(n - l):
                j = i + l
                dp[i][j] = dp[i + 1][j - 1] + 1
                for k in range(i, j):
                    if s[i] == s[k]:
                        dp[i][j] = min(dp[i][j], dp[i][k - 1] + dp[k + 1][j])
        return dp[0][n - 1]
